-- 2026-07-01: AI 채팅 좋아요/싫어요 피드백 테이블 생성
--
-- 배경: AiChatPanel 응답 하단 좋아요/싫어요 버튼 클릭 시 질문/답변/출처 스냅샷을 저장해
--       추후 답변 품질 분석에 활용한다. FEEDBACK_ID는 EQUIP_CONDITION_RULES.RULE_ID와
--       동일하게 Oracle IDENTITY(GENERATED BY DEFAULT AS IDENTITY)로 채번한다.

CREATE TABLE AI_CHAT_FEEDBACKS (
  FEEDBACK_ID   NUMBER          GENERATED BY DEFAULT AS IDENTITY,
  COMPANY       VARCHAR2(10)    NOT NULL,
  PLANT_CD      VARCHAR2(10)    NOT NULL,
  ROUTE         VARCHAR2(200),
  MENU_CODE     VARCHAR2(50),
  QUESTION      CLOB            NOT NULL,
  ANSWER        CLOB            NOT NULL,
  SOURCES_JSON  CLOB,
  RATING        VARCHAR2(10)    NOT NULL,
  CREATED_BY    VARCHAR2(50)    NOT NULL,
  CREATED_AT    TIMESTAMP       DEFAULT SYSTIMESTAMP NOT NULL,
  CONSTRAINT PK_AI_CHAT_FEEDBACKS PRIMARY KEY (FEEDBACK_ID),
  CONSTRAINT CK_AI_CHAT_FEEDBACKS_RATING CHECK (RATING IN ('LIKE','DISLIKE'))
)
/

CREATE INDEX IDX_AI_CHAT_FEEDBACKS_TENANT  ON AI_CHAT_FEEDBACKS (COMPANY, PLANT_CD)
/

CREATE INDEX IDX_AI_CHAT_FEEDBACKS_MENU    ON AI_CHAT_FEEDBACKS (MENU_CODE)
/

CREATE INDEX IDX_AI_CHAT_FEEDBACKS_CREATED ON AI_CHAT_FEEDBACKS (CREATED_AT DESC)
/

COMMIT
/
